export type ChannelRoadmapCategory =
  | "Player Channels"
  | "Team Channels"
  | "Era Channels"
  | "Event Channels"
  | "Chaos Channels"
  | "Talk Show / Studio Channels"
  | "Combat Sports Channels"
  | "Golf / Tennis / Individual Sports Channels"
  | "College Sports Channels"
  | "Compilation / Ambient Channels";

export type LaunchPriority = "next" | "soon" | "later";

export type ChannelRoadmapItem = {
  id: string;
  proposedChannelNumber: string;
  name: string;
  category: ChannelRoadmapCategory;
  sport: string;
  era: string;
  vibe: string;
  description: string;
  exampleMoments: string[];
  searchThemes: string[];
  avoid: string[];
  launchPriority: LaunchPriority;
  notes: string;
};

function slugify(name: string): string {
  return name
    .toLowerCase()
    .replace(/&/g, "and")
    .replace(/[^a-z0-9]+/g, "-")
    .replace(/^-|-$/g, "");
}

function ch(
  proposedChannelNumber: number,
  name: string,
  category: ChannelRoadmapCategory,
  sport: string,
  era: string,
  vibe: string,
  description: string,
  exampleMoments: string[],
  searchThemes: string[],
  avoid: string[],
  launchPriority: LaunchPriority,
  notes: string
): ChannelRoadmapItem {
  return {
    id: slugify(name),
    proposedChannelNumber: String(proposedChannelNumber).padStart(2, "0"),
    name,
    category,
    sport,
    era,
    vibe,
    description,
    exampleMoments,
    searchThemes,
    avoid,
    launchPriority,
    notes,
  };
}

